INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04270', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '非計劃性懷孕對女性來說是有壓力的，她接下來可能得面臨是否繼續或終止懷孕的問題。有關社 會工作者協助這樣的婦女，下列何者正確？', '["社工必須忠於個人的價值信念", "最終要讓懷孕婦女自己做決定，但社工是重要的引導者", "社工需要關注婦女的需求，而非僅協助婦女如何解決懷孕的問題", "如果最後的決定是基於男方的選擇和期待，社工就該充權婦女思考是否要繼續與男方的關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04271', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當兒童遭遇災難，或是目睹暴力，可能會受到很大的衝擊，甚至可能產生創傷後壓力症候群 （PTSD）。社會工作者在協助兒童和家庭因應創傷的作為上，下列那個做法較為適當？', '["孩子的生理照顧是最迫切的事，應以生理照顧為先、情緒照顧在後", "注意孩子行為的變化，尤其是過去和現在一直存在的問題行為", "照顧者是孩子重要依附對象，要協助照顧者找到讓孩子感受安全的方式", "孩子比較容易被誤導或有錯誤觀念，因此讓孩子知道一切所發生的事是重要的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04272', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成年期的女性常面臨角色期待的衝突，下列那種現象符合這個階段的描述？', '["職業婦女與家庭主婦相較之下，比較容易產生自責的心理調適問題，被稱之為「職業婦女症候群」", "近幾年，由於男性負擔家務的時間大幅增長，已經打破了「男主外、女主內」性別刻板化印象", "女性可能內化家庭及社會文化對角色的期待，讓自己陷於角色衝突", "無論是自願或非自願性選擇不生育子女，無子女成年女性的生活滿意度顯著低於同齡層有子女 的女性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04273', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '一般而言，女性兒童的攻擊行為較男童少。但是，女童的攻擊方式以間接方式較多。下列敘述的 間接攻擊方式何者錯誤？', '["散布謠言侮辱", "用網路背地講受害人壞話", "排擠受害人", "當面損毀受害人的用品"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04274', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據美國疾病預防中心的報告顯示，影響老年人生理健康的關鍵因素，下列何者錯誤？', '["睡眠", "飲食", "運動", "情緒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04275', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '一般企業對中高年齡勞工的負面印象可分為四大項，包含：身心機能、學習動機、觀念保守、反 應能力等。有關「反應能力降低」的敘述，下列何者錯誤？', '["抗拒改變", "不易適應", "缺乏創造力", "專業過時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04276', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據衛生福利部在 2016 年的調查顯示，國中生的網路成癮問題極為嚴重。網路成癮包含不同的 型態，有關網路成癮型態的敘述，下列何者錯誤？', '["網路性成癮：沉迷於聊天或遊戲", "網路人際關係成癮：網路關係取代真實的生活", "網路強迫症：沉迷上網購物或賭博", "網路恐慌症：沉迷於網路漫遊或搜尋資訊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04277', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關人類行為與社會環境重要性的敘述，下列組合何者正確？①社會工作者為了適應環境改變，', '["社會工作者在面臨問題時，應藉由整體的 觀點來思考如何有效地提供服務", "案主來自不同的族群背景，呈現不同的態度與觀念；每個人 在其生命過程上有不同的遭遇與差異", "人類行為採用整合性多面向途徑，在處理社會工作的服 務議題時，其效果有限", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04278', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '成人中期的精神疾病逐漸受到關切，有關「創傷後壓力症候群（PTSD）」的症狀，下列組合何者', '["重複出現夢境、回憶的畫面", "逃避與創傷有關的刺激物", "與平常生活有關的社會問 題", "有攻擊行為或過度驚嚇的反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04279', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童長期看電視可能會造成腦部發育的負面影響，下列現象組合何者正確？①思考能力降低', '["智力發展受損", "閱讀能力下降", "情緒智能降低", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:24+00:00", "source_pdf_sha1": "a4b40e455ae4", "answer_pdf_sha1": "955d01199b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
